import React, { useEffect, useState } from 'react';
import './RegisterProductionRequirement.css';

const ProductionRequirementsList = ({ onEdit }) => {
    const [requirements, setRequirements] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        const fetchRequirements = async () => {
            try {
                const response = await fetch('http://localhost:8000/api/v1/production-requirements');
                if (!response.ok) throw new Error('Failed to fetch requirements');
                setRequirements(await response.json());
            } catch (err) {
                setError('Could not load production requirements.');
            } finally {
                setLoading(false);
            }
        };
        fetchRequirements();
    }, []);

    const handleDelete = async (id) => {
        if (!window.confirm('Delete this production requirement?')) return;
        try {
            const response = await fetch(`http://localhost:8000/api/v1/production-requirements/${id}`, { method: 'DELETE' });
            if (!response.ok) throw new Error('Delete failed');
            setRequirements(requirements.filter(r => r.id !== id));
        } catch (err) {
            setError('Delete failed.');
        }
    };

    if (loading) return <div>Loading...</div>;
    if (error) return <div className="error">{error}</div>;
    return (
        <div className="production-requirements-list">
            <h2>Production Requirements List</h2>
            <table>
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Product</th>
                        <th>Raw Materials</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    {requirements.map(req => (
                        <tr key={req.id}>
                            <td>{req.id}</td>
                            <td>{req.productId}</td>
                            <td>
                                {req.requirements.map((item, idx) => (
                                    <div key={idx}>RawMaterial: {item.rawMaterialId}, Qty: {item.quantity}</div>
                                ))}
                            </td>
                            <td>
                                <button onClick={() => onEdit(req)}>Edit</button>
                                <button onClick={() => handleDelete(req.id)}>Delete</button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default ProductionRequirementsList;
